  ('customs-6f0ba476-moex-00141', 'customs-6f0ba476', 'customs-6f0ba476-moex-111-f6c431ec', 'sub-customs-6f0ba476-04', NULL, 'essay', '一地區有 A、B、C三人，舉辦兩議案之公投：甲案為廣設電子監控系統，
乙案為引進石化廠。對於此二議案，三人對甲案的主張為：A、B贊成（多
數人贊成），C反對（少數人反對）；對乙案的主張為：A反對（少數人
反對），B、C 贊成（多數人贊成）。假設當個人處於少數人立場時，其
偏好相對較處於多數人立場時強烈。執政黨對兩議案都站在多數人的立
場，亦即主張廣設電子監控系統，以增進地區安全，並且歡迎石化廠進駐，
以促進地區繁榮發展。何謂簡單多數決？在簡單多數決的投票法則下，其
他政黨對兩議案有無可能提出政見主張以獲得多數人的支持？請分析並
詳細說明。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:16+00:00", "source_pdf_sha1": "9bad83a91448", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "101", "s": "1001", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "財政學", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "財稅行政"}'::jsonb, NULL),
